import React from "react";
import styled from "styled-components";
import { Link } from "react-router-dom";
import PageBanner from "../components/ui/PageBanner";
import Card from "../components/ui/Card";
import CallToAction from "../components/sections/CallToAction";

/**
 * NewsEvents - Component for displaying news and events
 * @returns {JSX.Element} The NewsEvents component
 */
const NewsEvents = () => {
  return (
    <>
      <PageBanner 
        title="News & Events" 
        subtitle="Stay updated with our latest news, events, and stories from the field" 
      />

      <NewsEventsSection>
        <SectionContent>
          <TabsContainer>
            <TabLink to="/news-events" active={true}>All</TabLink>
            <TabLink to="/news-events/blog">Blog</TabLink>
            <TabLink to="/news-events/announcements">Announcements</TabLink>
            <TabLink to="/news-events/gallery">Photo Gallery</TabLink>
          </TabsContainer>

          <SectionTitle>Latest News & Updates</SectionTitle>

          <FeaturedNews>
            <FeaturedImage style={{ backgroundImage: "url('/images/news/featured-news.jpg')" }}>
              <FeaturedCategory>Announcement</FeaturedCategory>
            </FeaturedImage>
            <FeaturedContent>
              <FeaturedDate>June 15, 2023</FeaturedDate>
              <FeaturedTitle>Pathway Foundation Launches New Youth Leadership Program</FeaturedTitle>
              <FeaturedDescription>
                We are excited to announce the launch of our new Youth Leadership Program, aimed at empowering young people with the skills and opportunities to become effective leaders in their communities.
              </FeaturedDescription>
              <ReadMoreLink to="/news-events/announcements/youth-leadership-program">Read More</ReadMoreLink>
            </FeaturedContent>
          </FeaturedNews>

          <NewsGrid>
            {[...Array(6)].map((_, index) => (
              <Card 
                key={index}
                title={`News Title ${index + 1}`}
                description={`Short description for news item ${index + 1}. This is a brief overview of the article content.`}
                image={`/images/news/news-${index + 1}.jpg`}
                imageAlt={`News image ${index + 1}`}
                link={`/news-events/blog/article-${index + 1}`}
              />
            ))}
          </NewsGrid>

          <UpcomingEventsSection>
            <SectionTitle>Upcoming Events</SectionTitle>
            <EventsGrid>
              {[...Array(3)].map((_, index) => (
                <EventCard key={index}>
                  <EventDate>
                    <EventDay>{15 + index}</EventDay>
                    <EventMonth>JUL</EventMonth>
                  </EventDate>
                  <EventDetails>
                    <EventTitle>Community Outreach Event {index + 1}</EventTitle>
                    <EventMeta>
                      <EventTime>10:00 AM - 2:00 PM</EventTime>
                      <EventLocation>Dar es Salaam, Tanzania</EventLocation>
                    </EventMeta>
                    <EventDescription>
                      Join us for a community outreach event where we will be providing health screenings, educational resources, and more.
                    </EventDescription>
                    <EventLink to={`/events/event-${index + 1}`}>Learn More</EventLink>
                  </EventDetails>
                </EventCard>
              ))}
            </EventsGrid>
          </UpcomingEventsSection>
        </SectionContent>
      </NewsEventsSection>

      <CallToAction />
    </>
  );
};

// Styled components
const NewsEventsSection = styled.section`
  padding: 80px 0;
  background-color: var(--background-white);
`;

const SectionContent = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
`;

const TabsContainer = styled.div`
  display: flex;
  border-bottom: 1px solid var(--border-color);
  margin-bottom: 40px;
  overflow-x: auto;

  @media (max-width: 768px) {
    padding-bottom: 10px;
  }
`;

const TabLink = styled(Link)`
  padding: 12px 24px;
  color: ${props => props.active ? "var(--primary-color)" : "var(--text-secondary)"};
  font-weight: ${props => props.active ? "600" : "400"};
  border-bottom: 3px solid ${props => props.active ? "var(--primary-color)" : "transparent"};
  margin-bottom: -1px;
  white-space: nowrap;

  &:hover {
    color: var(--primary-color);
  }
`;

const SectionTitle = styled.h2`
  font-size: 28px;
  margin-bottom: 30px;
  color: var(--text-primary);
`;

const FeaturedNews = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 30px;
  margin-bottom: 60px;
  background-color: var(--background-light);
  border-radius: 12px;
  overflow: hidden;

  @media (max-width: 1024px) {
    grid-template-columns: 1fr;
  }
`;

const FeaturedImage = styled.div`
  height: 100%;
  min-height: 300px;
  background-size: cover;
  background-position: center;
  position: relative;

  @media (max-width: 1024px) {
    height: 300px;
  }
`;

const FeaturedCategory = styled.span`
  position: absolute;
  top: 20px;
  left: 20px;
  background-color: var(--primary-color);
  color: white;
  padding: 6px 12px;
  border-radius: 4px;
  font-size: 14px;
  font-weight: 500;
`;

const FeaturedContent = styled.div`
  padding: 40px;
  display: flex;
  flex-direction: column;
`;

const FeaturedDate = styled.span`
  font-size: 14px;
  color: var(--text-secondary);
  margin-bottom: 16px;
`;

const FeaturedTitle = styled.h3`
  font-size: 24px;
  margin-bottom: 16px;
  color: var(--text-primary);
`;

const FeaturedDescription = styled.p`
  font-size: 16px;
  line-height: 1.6;
  color: var(--text-secondary);
  margin-bottom: 24px;
  flex-grow: 1;
`;

const ReadMoreLink = styled(Link)`
  color: var(--primary-color);
  font-weight: 500;
  display: inline-flex;
  align-items: center;

  &::after {
    content: "→";
    margin-left: 6px;
    transition: transform 0.2s ease;
  }

  &:hover::after {
    transform: translateX(4px);
  }
`;

const NewsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 30px;
  margin-bottom: 80px;

  @media (max-width: 1024px) {
    grid-template-columns: repeat(2, 1fr);
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const UpcomingEventsSection = styled.div`
  margin-top: 80px;
`;

const EventsGrid = styled.div`
  display: grid;
  grid-template-columns: 1fr;
  gap: 20px;
`;

const EventCard = styled.div`
  display: flex;
  background-color: var(--background-light);
  border-radius: 12px;
  overflow: hidden;

  @media (max-width: 768px) {
    flex-direction: column;
  }
`;

const EventDate = styled.div`
  background-color: var(--primary-color);
  color: white;
  padding: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-width: 100px;

  @media (max-width: 768px) {
    padding: 10px;
    flex-direction: row;
    gap: 10px;
  }
`;

const EventDay = styled.div`
  font-size: 28px;
  font-weight: 700;
`;

const EventMonth = styled.div`
  font-size: 16px;
  text-transform: uppercase;
`;

const EventDetails = styled.div`
  padding: 20px;
  flex-grow: 1;
`;

const EventTitle = styled.h3`
  font-size: 20px;
  margin-bottom: 12px;
  color: var(--text-primary);
`;

const EventMeta = styled.div`
  display: flex;
  gap: 20px;
  margin-bottom: 12px;
  color: var(--text-secondary);
  font-size: 14px;

  @media (max-width: 768px) {
    flex-direction: column;
    gap: 6px;
  }
`;

const EventTime = styled.span``;

const EventLocation = styled.span``;

const EventDescription = styled.p`
  font-size: 16px;
  line-height: 1.6;
  color: var(--text-secondary);
  margin-bottom: 16px;
`;

const EventLink = styled(Link)`
  color: var(--primary-color);
  font-weight: 500;
`;

export default NewsEvents;
